it("should let a live cell with 4 live neighbors die (overpopulation)", () => {
  // ###   <- (0,0), (1,0), (2,0)
  // .#.   <- (1,1) has 4 live neighbors -> dies
  // ###   <- (0,2), (1,2), (2,2)
  const nextGen = nextGeneration([
    [0, 0],
    [1, 0],
    [2, 0],
    [1, 1],
    [0, 2],
    [1, 2],
    [2, 2],
  ]);
  expect(nextGen).not.toContainEqual([1, 1]);
});
